### 5. New file: `src/components/chess-game/ui/PromotionPicker.tsx`

Uses `defaultPieces` from `react-chessboard` (already a dep; exports `PieceRenderObject`).

**Export pure coordinate helper** (so it can be unit-tested in isolation):
```ts
export function squareToPercent(
  square: string,
  orientation: 'white' | 'black'
): { left: number; top: number } {
  const file = 'abcdefgh'.indexOf(square[0]);  // 0=a, 7=h
  const rank = parseInt(square[1]) - 1;         // 0=rank1, 7=rank8
  const col = orientation === 'white' ? file : 7 - file;
  const row = orientation === 'white' ? 7 - rank : rank;
  return { left: col * 12.5, top: row * 12.5 };
}
```

**Stack direction**: `top < 50` → stack downward (+12.5% per slot); else upward (-12.5%).

**Piece order**: Q, R, B, N.

**Piece key**: `playerColor === 'white' ? 'wQ' : 'bQ'` etc., from `defaultPieces`.

```tsx
import { defaultPieces } from 'react-chessboard';

const PROMO_PIECES = ['q', 'r', 'b', 'n'] as const;

export function PromotionPicker({ targetSquare, playerColor, boardOrientation, onPick, onCancel }) {
  const { left, top } = squareToPercent(targetSquare, boardOrientation);
  const direction = top < 50 ? 1 : -1;
  const colorPrefix = playerColor === 'white' ? 'w' : 'b';

  return (
    <>
      <div className="promotion-picker-backdrop" onClick={onCancel} />
      {PROMO_PIECES.map((piece, i) => {
        const PieceSvg = defaultPieces[colorPrefix + piece.toUpperCase() as keyof typeof defaultPieces];
        return (
          <button
            key={piece}
            className="promotion-picker-square"
            style={{ left: `${left}%`, top: `${top + direction * i * 12.5}%` }}
            onClick={(e) => { e.stopPropagation(); onPick(piece); }}
            aria-label={`Promote to ${piece}`}
          >
            <PieceSvg />
          </button>
        );
      })}
    </>
  );
}
```

